exercises.solution_code:
def take(iterable, n):
    iterator = iter(iterable)
    result = []
    for _ in range(n):
        try:
            result.append(next(iterator))
        except StopIteration:
            break
    return result

tests.content:
import pytest

from solution import take


def test_takes_first_n_from_list():
    assert take([10, 20, 30, 40], 2) == [10, 20]


def test_n_zero_returns_empty():
    assert take([1, 2, 3], 0) == []


def test_stops_when_iterable_is_shorter_than_n():
    # Asking for more than is available must not raise; just return what exists.
    assert take([1, 2], 5) == [1, 2]


def test_empty_iterable():
    assert take([], 3) == []


def test_consumes_an_iterator_only_partially():
    # Tricky: take must call next() exactly n times, not exhaust the iterator.
    it = iter([1, 2, 3, 4, 5])
    first = take(it, 2)
    assert first == [1, 2]
    # The same underlying iterator should continue where take left off.
    assert next(it) == 3, "take must not consume more than n items"


def test_works_on_a_one_shot_iterator():
    # A generator is a one-shot iterator: there is no len(), no indexing.
    def gen():
        yield "a"
        yield "b"
        yield "c"

    assert take(gen(), 2) == ["a", "b"]


def test_does_not_use_len_or_indexing():
    # An object that is iterable but has neither __len__ nor __getitem__
    # must still work, proving take relies only on the iterator protocol.
    class CountUp:
        def __init__(self, stop):
            self.stop = stop

        def __iter__(self):
            i = 0
            while i < self.stop:
                yield i
                i += 1

    assert take(CountUp(4), 3) == [0, 1, 2]

