exercises.solution_code:
class Cycle:
    """A reusable iterable that yields the given items `times` times in order.

    Cycle is an *iterable*, not an iterator: each call to iter() must produce a
    fresh, independent iterator, so the same Cycle can be looped over again.
    """

    def __init__(self, items, times):
        self.items = list(items)
        self.times = times

    def __iter__(self):
        return _CycleIterator(self.items, self.times)


class _CycleIterator:
    def __init__(self, items, times):
        self.items = items
        self.times = times
        self.round = 0
        self.index = 0

    def __iter__(self):
        return self

    def __next__(self):
        if self.round >= self.times or not self.items:
            raise StopIteration
        value = self.items[self.index]
        self.index += 1
        if self.index >= len(self.items):
            self.index = 0
            self.round += 1
        return value

