exercises.solution_code:
class Chain:
    """Lazily iterate over several iterables as if they were one sequence.

    Chain is an iterable. Each call to iter() yields a fresh iterator that walks
    the sources left to right, pulling items lazily via the iterator protocol.
    Sources are only iterated when actually reached.
    """

    def __init__(self, *sources):
        self.sources = sources

    def __iter__(self):
        return _ChainIterator(self.sources)


class _ChainIterator:
    def __init__(self, sources):
        # Keep an iterator over the sources themselves, plus the current inner one.
        self._source_iter = iter(sources)
        self._current = None

    def __iter__(self):
        return self

    def __next__(self):
        while True:
            if self._current is None:
                # Advance to the next source; iter() it lazily, only when reached.
                self._current = iter(next(self._source_iter))
            try:
                return next(self._current)
            except StopIteration:
                # Current source exhausted; move on to the next one.
                self._current = None
